function getImagesForEx(exId, userImages) {
  if (userImages?.[exId]?.length) return userImages[exId];
  if (EMBEDDED_IMGS[exId]?.length) return EMBEDDED_IMGS[exId];
  const ids = UNSPLASH_IMGS[exId];
  if (ids) return ids.map(id => `https://images.unsplash.com/photo-${id}?w=600&h=400&fit=crop&q=85`);
  // Picsum fallback
  const seed = Math.abs(exId.split("").reduce((a,c)=>a+c.charCodeAt(0),0));
  return [`https://picsum.photos/seed/${seed}/600/400`, `https://picsum.photos/seed/${seed+1}/600/400`];
}


// ─── AI CALL (básico) ────────────────────────────────────────────────────────
async function callAI(messages, maxTokens = 1000) {
  const res = await fetch("/api/ai", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ messages, max_tokens: maxTokens }),
  });
  const d = await res.json();
  if (d.error) throw new Error(d.error);
  return d.text;
}

// ─── AI CALL COM WEB SEARCH ──────────────────────────────────────────────────
// Usa a tool web_search no body (sem header beta) — funciona no sandbox claude.ai
async function callAIWithSearch(messages) {
  const res = await fetch("/api/ai/search", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ messages }),
  });
  const d = await res.json();
  if (d.error) throw new Error(d.error);
  return d.text;
}

