                    <input type="file" accept="image/*" ref={fileRef} onChange={e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=ev=>setFotoData(ev.target.result);r.readAsDataURL(f);}} style={{display:"none"}} />
